public UniformDataGenerator(int constructorId, final int seed) {
    if (constructorId == 0) {

                this.rand = new Random(seed);
            }
    else {

                this.rand = new Random();
            }
}

int[] generateUniformBitmap(int N, int Max) {
        if (N > Max)
                throw new RuntimeException("not possible");
        int[] ans = new int[N];
        BitSet bs = new BitSet(Max);
        int cardinality = 0;
        while (cardinality < N) {
                int v = rand.nextInt(Max);
                if (!bs.get(v)) {
                        bs.set(v);
                        cardinality++;
                }
        }
        int pos = 0;
        for (int i = bs.nextSetBit(0); i >= 0; i = bs.nextSetBit(i + 1)) {
                ans[pos++] = i;
        }
        return ans;
}

int[] generateUniformHash(int N, int Max) {
        if (N > Max)
                throw new RuntimeException("not possible");
        int[] ans = new int[N];
        HashSet<Integer> s = new HashSet<Integer>();
        while (s.size() < N)
                s.add(new Integer(this.rand.nextInt(Max)));
        Iterator<Integer> i = s.iterator();
        for (int k = 0; k < N; ++k)
                ans[k] = i.next().intValue();
        Arrays.sort(ans);
        return ans;
}
